pub struct SpcVerificationError {
    pub message: String,
}

impl fmt::Display for SpcVerificationError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "SPC verification error: {}", self.message)
    }
}

impl std::error::Error for SpcVerificationError {}

impl From<String> for SpcVerificationError {
    fn from(message: String) -> Self {
        Self { message }
    }
}

pub trait SpcVerifier: Send + Sync {
    type Error: std::error::Error + Send + Sync + 'static;

    fn verify_batch(
        &self,
        requests: Vec<SpcVerificationRequest>,
        max_parallelism: usize,
    ) -> Pin<Box<dyn Future<Output = Result<BatchVerificationResult, Self::Error>> + Send + '_>>;

    fn verify_parallel_optimized(
        &self,
        requests: Vec<SpcVerificationRequest>,
    ) -> Pin<Box<dyn Future<Output = Result<BatchVerificationResult, Self::Error>> + Send + '_>>;

    fn get_previous_block_data(&self, block_number: u64) -> Result<(B256, u64, u64), Self::Error>;

    fn ensure_registry_synced(
        &self,
        needed_block: u64,
    ) -> Pin<Box<dyn Future<Output = Result<(), Self::Error>> + Send + '_>>;

    fn update_registry_from_data(
        &self,
        executors: Vec<(Address, Address, u8, Vec<u8>, alloy_primitives::FixedBytes<32>, u8)>,
        block_number: u64,
    ) -> Result<(), Self::Error>;
}

